    event.preventDefault();
    try {
      setSaving(true);
      const payload = {
        pondCode: form.pondCode.trim() || undefined,
        pondName: form.pondName.trim(),
        areaMeter: Number(form.area_m2),
        depthMeter: Number(form.depth_m),
        maxDensity: Number(form.max_density),
        assignedStaff: form.assigned_staff ? Number(form.assigned_staff) : null
      };
      if (editingPond) {
        await pondService.updatePond(editingPond.pond_id, payload);
        pushToast({
          title: "Thành công",
          message: 'Cáº­p nháº­t ao nuÃ´i thÃ nh cÃ´ng',
          type: "success"
        });
      } else {
        await pondService.createPond(payload);
        pushToast({
          title: "Thành công",
          message: 'Táº¡o ao nuÃ´i thÃ nh cÃ´ng',
          type: "success"
        });
      }
      setShowModal(false);
      setEditingPond(null);
      setForm(emptyForm);
      await fetchData();
    } catch (err) {
      pushToast({
        title: "Thất bại",
        message: err?.response?.data?.message || 'Lá»—i khi lÆ°u dá»¯ liá»‡u',
        type: "error"
      });
    } finally {
      setSaving(false);
    }
  };
  const handleDelete = async pondId => {
    if (window.confirm('Báº¡n cháº¯c cháº¯n muá»‘n xÃ³a ao nuÃ´i nÃ y?')) {
      try {
        await pondService.deletePond(pondId);
        pushToast({
          title: "Thành công",
          message: 'XÃ³a ao nuÃ´i thÃ nh cÃ´ng',
          type: "success"
        });
        await fetchData();
      } catch (err) {
        pushToast({
          title: "Thất bại",
          message: err?.response?.data?.message || 'Lá»—i khi xÃ³a ao nuÃ´i',
          type: "error"
        });
      }
    }
  };
  if (loading) {
    return <div className="owner-ponds owner-page">
        <div className="flex-center" style={{
        height: '100vh'
      }}>
          <div className="spinner"></div>
        </div>
      </div>;
  }
  return <div className="owner-ponds owner-page">
      <div className="owner-page__header" style={{
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      gap: '16px'
    }}>
        <div>
          <h1>Quáº£n lÃ½ ao nuÃ´i</h1>
          <p>Tá»•ng sá»‘ ao: {ponds.length}</p>
        </div>
        <button onClick={openCreateModal} className="btn btn-primary">
          âž• ThÃªm ao má»›i
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div className="card">
        <table className="data-table" style={{
        width: '100%',
        borderCollapse: 'collapse'
      }}>
          <thead>
            <tr style={{
            borderBottom: '2px solid #ddd'
          }}>
              <th style={{
              padding: '12px',
              textAlign: 'left',
              fontWeight: 600
            }}>MÃ£ ao</th>
              <th style={{
              padding: '12px',
              textAlign: 'left',
              fontWeight: 600
            }}>TÃªn ao</th>
              <th style={{
              padding: '12px',
              textAlign: 'left',
              fontWeight: 600
            }}>Diá»‡n tÃ­ch (mÂ²)</th>
              <th style={{
              padding: '12px',
              textAlign: 'left',
              fontWeight: 600
            }}>Äá»™ sÃ¢u (m)</th>
              <th style={{
              padding: '12px',
              textAlign: 'left',
              fontWeight: 600
            }}>Máº­t Ä‘á»™ tá»‘i Ä‘a</th>
              <th style={{
              padding: '12px',
              textAlign: 'left',
              fontWeight: 600
            }}>NgÆ°á»i phá»¥ trÃ¡ch</th>
              <th style={{
              padding: '12px',
              textAlign: 'center',
              fontWeight: 600
            }}>HÃ nh Ä‘á»™ng</th>
            </tr>
          </thead>
          <tbody>
