              textAlign: 'center'
            }}>
                    <button onClick={() => openEditModal(pond)} className="btn btn-secondary" style={{
                marginRight: '8px',
                padding: '4px 8px',
                fontSize: '0.85rem'
              }}>
                      âœï¸ Sá»­a
                    </button>
                    <button onClick={() => handleDelete(pond.pond_id)} className="btn btn-danger" style={{
                padding: '4px 8px',
                fontSize: '0.85rem'
              }}>
                      ðŸ—‘ï¸ XÃ³a
                    </button>
                  </td>
                </tr>)}
          </tbody>
        </table>
      </div>

      {showModal && <div className="modal">
          <div className="modal-content owner-page__modal">
            <h2 className="owner-page__section-title">{editingPond ? 'Sá»­a ao nuÃ´i' : 'Táº¡o ao nuÃ´i má»›i'}</h2>
            <form onSubmit={handleSubmit}>
              <div className="owner-page__form-grid">
                {editingPond && <div className="owner-page__form-group owner-page__form-group--full">
                    <label htmlFor="pondCode">MÃ£ ao</label>
                    <input id="pondCode" type="text" value={form.pondCode} onChange={e => handleChange('pondCode', e.target.value)} placeholder="Äá»ƒ trá»‘ng Ä‘á»ƒ tá»± sinh" />
                  </div>}
                <div className="owner-page__form-group">
                  <label htmlFor="pondName">TÃªn ao *</label>
                  <input id="pondName" type="text" value={form.pondName} onChange={e => handleChange('pondName', e.target.value)} placeholder="Nháº­p tÃªn ao" required />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="area_m2">Diá»‡n tÃ­ch (mÂ²) *</label>
                  <input id="area_m2" type="number" value={form.area_m2} onChange={e => handleChange('area_m2', e.target.value)} placeholder="Nháº­p diá»‡n tÃ­ch" required />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="depth_m">Äá»™ sÃ¢u (m) *</label>
                  <input id="depth_m" type="number" value={form.depth_m} onChange={e => handleChange('depth_m', e.target.value)} placeholder="Nháº­p Ä‘á»™ sÃ¢u" required />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="max_density">Máº­t Ä‘á»™ tá»‘i Ä‘a *</label>
                  <input id="max_density" type="number" value={form.max_density} onChange={e => handleChange('max_density', e.target.value)} placeholder="Nháº­p máº­t Ä‘á»™ tá»‘i Ä‘a" required />
                </div>
                <div className="owner-page__form-group">
                  <label htmlFor="assigned_staff">NgÆ°á»i phá»¥ trÃ¡ch (tÃ¹y chá»n)</label>
                  {staffOptions.length === 0 ? <div style={{
                padding: '10px',
                backgroundColor: '#f0f0f0',
                borderRadius: '4px',
                color: '#666',
                fontSize: '0.9rem'
              }}>
                      â„¹ï¸ ChÆ°a cÃ³ nhÃ¢n viÃªn nÃ o. HÃ£y táº¡o nhÃ¢n viÃªn trong trang Quáº£n lÃ½ nhÃ¢n viÃªn.
                    </div> : <select id="assigned_staff" value={form.assigned_staff} onChange={e => handleChange('assigned_staff', e.target.value)}>
                      <option value="">-- Chá»n nhÃ¢n viÃªn --</option>
                      {staffOptions.map(staff => <option key={staff.id} value={staff.id}>
                          {staff.name}
                        </option>)}
